USE P21Play;
SET NOCOUNT ON;

DECLARE @definition nvarchar(max)=OBJECT_DEFINITION(OBJECT_ID('dbo.p21_fnt_get_linkable_transactions'));
DECLARE @chunks int = CONVERT(int, CEILING(CONVERT(decimal(19,4), LEN(@definition)) / 3500.0));

SELECT
      parameter_id=CONVERT(nvarchar(20), p.parameter_id)
    , parameter_name=p.name
    , type_name=TYPE_NAME(p.user_type_id)
    , max_length=CONVERT(nvarchar(20), p.max_length)
FROM sys.parameters AS p
WHERE p.object_id=OBJECT_ID('dbo.p21_fnt_get_linkable_transactions')
ORDER BY p.parameter_id;

;WITH n AS (
    SELECT TOP (@chunks)
           rn = ROW_NUMBER() OVER (ORDER BY (SELECT NULL))
    FROM sys.all_objects
)
SELECT
      chunk_no=CONVERT(nvarchar(20), rn)
    , chunk_text=SUBSTRING(@definition, ((rn - 1) * 3500) + 1, 3500)
FROM n
ORDER BY rn;
